import { PrismaClient } from "@prisma/client";
const prisma = new PrismaClient();

async function withRetry<T>(fn: () => Promise<T>, retries = 5, delay = 5000): Promise<T> {
  for (let i = 0; i < retries; i++) {
    try { return await fn(); } catch (e: any) {
      if (i < retries - 1 && (e?.message?.includes("Can't reach database") || e?.message?.includes("connect"))) {
        console.log(`  ⏳ DB retry ${i+2}/${retries}...`);
        await new Promise(r => setTimeout(r, delay));
      } else throw e;
    }
  }
  throw new Error("Max retries");
}

type Q = { topic: string; year: number; questionText: string; optionA: string; optionB: string; optionC: string; optionD: string; correctOption: "A"|"B"|"C"|"D"; explanation: string; difficulty: "EASY"|"MEDIUM"|"HARD"; };

async function warmUp() {
  for (let i = 0; i < 15; i++) {
    try { await prisma.$queryRaw`SELECT 1`; console.log("  ✓ DB connected"); return; }
    catch { console.log(`  Warming up... ${i+1}/15`); await new Promise(r => setTimeout(r, 5000)); }
  }
  throw new Error("Could not connect");
}

async function seedSubject(name: string, level: string, examType: string, questions: Q[]) {
  const subject = await withRetry(() => prisma.subject.findFirst({ where: { name, level } }));
  if (!subject) { console.log(`  ${name} not found!`); return 0; }
  let totalCreated = 0;
  const batchSize = 50;
  for (let i = 0; i < questions.length; i += batchSize) {
    const batch = questions.slice(i, i + batchSize);
    try {
      const result = await withRetry(() => prisma.question.createMany({
        data: batch.map(q => ({
          level, examType: examType as any, subjectId: subject.id,
          topic: q.topic, year: q.year, questionText: q.questionText,
          optionA: q.optionA, optionB: q.optionB, optionC: q.optionC, optionD: q.optionD,
          correctOption: q.correctOption, explanation: q.explanation, difficulty: q.difficulty as any,
        })),
        skipDuplicates: true,
      }));
      totalCreated += result.count;
      console.log(`  ${name}: batch ${Math.floor(i/batchSize)+1} - ${result.count} created`);
    } catch (err: any) { console.log(`  ${name}: batch error - ${err.message.slice(0,80)}`); }
  }
  console.log(`  ${name}: ${totalCreated} total`);
  return totalCreated;
}

